"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { getDashboardPathForRole } from "../../../lib/auth";
import RecordCard from "../../patient/components/RecordCard";

export default function PatientDashboard() {
  const [patient, setPatient] = useState<any | null>(null);
  const [records, setRecords] = useState<any[]>([]);
  const router = useRouter();

  useEffect(() => {
    const init = async () => {
      const stored = localStorage.getItem("user");

      if (!stored) {
        router.replace("/auth/login");
        return;
      }

      const user = JSON.parse(stored);

      // Only PATIENTs can access this dashboard
      if (user.role !== "PATIENT") {
        const target = getDashboardPathForRole(user.role);
        router.replace(target);
        return;
      }

      // Fetch patient profile
      const profileRes = await fetch(
        `http://localhost:5000/api/patient/${user.patientId}`,
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        }
      );

      const profileData = await profileRes.json();
      setPatient(profileData);

      // Fetch medical history
      const historyRes = await fetch(
        `http://localhost:5000/api/patient/${user.patientId}/history`,
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        }
      );

      const historyData = await historyRes.json();
      setRecords(historyData);
    };

    init();
  }, []);

  return (
    <div className="space-y-6">
      <h1 className="text-xl font-bold mb-4">Patient Dashboard</h1>

      {/* Profile Section */}
      {patient && (
        <div className="bg-white p-4 rounded shadow">
          <h2 className="text-lg font-semibold mb-2">My Profile</h2>
          <p>
            <strong>Name:</strong> {patient.name}
          </p>
          <p>
            <strong>Patient ID:</strong> {patient.patientId}
          </p>
          <p>
            <strong>Age:</strong> {patient.age}
          </p>
          <p>
            <strong>Gender:</strong> {patient.gender}
          </p>
          <p>
            <strong>Address:</strong> {patient.address}
          </p>
        </div>
      )}

      {/* History Section (same info as /patient/history) */}
      <div>
        <h2 className="text-lg font-semibold mb-3">My Medical History</h2>
        <div className="space-y-4">
          {records.map((record, index) => (
            <RecordCard key={index} record={record} />
          ))}
        </div>
      </div>
    </div>
  );
}