interface Props {
  record: any;
}

const IPFS_GATEWAY = "https://gateway.pinata.cloud/ipfs/";

export default function RecordCard({ record }: Props) {
  const fileUrl = `${IPFS_GATEWAY}${record.ipfsHash}`;

  return (
    <div className="bg-white p-4 rounded shadow">
      <p><strong>Disease:</strong> {record.disease}</p>
      <p><strong>Symptoms:</strong> {record.symptoms.join(", ")}</p>
      <p><strong>Prescription:</strong> {record.prescription}</p>
      <p><strong>Hospital:</strong> {record.hospitalName}</p>
      <p><strong>Date:</strong> {new Date(record.date).toDateString()}</p>

      <a
        href={fileUrl}
        target="_blank"
        className="text-blue-600 underline mt-2 inline-block"
      >
        View Report (IPFS)
      </a>
    </div>
  );
}